async (page) => {
  async function executeSQL(sql) {
    // Clear editor and type new SQL
    const editor = await page.$('.monaco-editor');
    await editor.click();
    await page.keyboard.press('Control+a');
    await page.keyboard.type(sql);
    await page.waitForTimeout(500);

    // Click SQL检查
    const buttons = await page.$$('button');
    for (const btn of buttons) {
      const text = await btn.textContent();
      if (text.trim() === 'SQL检查') {
        await btn.click();
        await page.waitForTimeout(1500);
        break;
      }
    }

    // Click 提交
    const buttons2 = await page.$$('button');
    for (const btn of buttons2) {
      const text = await btn.textContent();
      const disabled = await btn.getAttribute('disabled');
      if (text.trim() === '提交' && !disabled) {
        await btn.click();
        await page.waitForTimeout(3000);
        break;
      }
    }

    // Get results
    const tables = await page.$$('table');
    let result = '';
    for (const t of tables) {
      const text = await t.textContent();
      if (text.length > 20) {
        result = text.trim();
        break;
      }
    }
    return result || 'no result';
  }

  const sql1 = "SELECT id, cash_ratio_decimal, red_ratio_decimal, ratio_mode FROM wm_ad_sdf_activity WHERE ratio_mode=0 AND status=1 LIMIT 1";
  const result1 = await executeSQL(sql1);
  return 'SQL1: ' + result1.substring(0, 500);
}

